// Per-project dedup against THIS project's own engagement_log.json --
// never a shared cross-project file (C2). Plus a 7-day GLOBAL coherence
// window against a separate, deliberately shared file -- so the same
// person doesn't get conflicting drafts from two projects within days,
// without permanently blocking future engagement (the distinction that
// matters vs. a permanent suppression file).

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const prefix = $json.project_prefix;
const contacts = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'contacts.json'), 'utf8')).filter(c => c.valid_format);

let localLog = [];
try { localLog = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'engagement_log.json'), 'utf8')); } catch (e) {}
const localSeen = new Set(localLog.map(l => l.email));

let globalHistory = {};
try { globalHistory = JSON.parse(fs.readFileSync(path.join('Shared', 'global_engagement_history.json'), 'utf8')); } catch (e) {}

const now = Date.now();
const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;

const eligible = contacts.filter(c => {
  if (localSeen.has(c.email)) return false;
  const hash = crypto.createHash('sha256').update(c.email.toLowerCase().trim()).digest('hex');
  const lastGlobal = globalHistory[hash];
  if (lastGlobal && (now - new Date(lastGlobal).getTime()) < SEVEN_DAYS_MS) return false;
  return true;
});

// Undone rows roll into today ahead of new picks -- local log tracks
// draft-generated-but-not-yet-posted separately; this simplified pass
// prioritizes never-yet-drafted contacts first.
const picks = eligible.slice(0, 30);

return picks.map(c => ({ json: { project_prefix: prefix, ...c } }));

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

// Record locally (per-project) AND update the shared 7-day coherence
// window -- two different writes, two different purposes.
const prefix = $json.project_prefix;
let localLog = [];
try { localLog = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'engagement_log.json'), 'utf8')); } catch (e) {}
localLog.push({ email: $json.email, drafted_at: new Date().toISOString() });
fs.writeFileSync(path.join('Working', prefix, 'engagement_log.json'), JSON.stringify(localLog, null, 2), 'utf8');

let globalHistory = {};
const ghPath = path.join('Shared', 'global_engagement_history.json');
try { globalHistory = JSON.parse(fs.readFileSync(ghPath, 'utf8')); } catch (e) {}
const hash = crypto.createHash('sha256').update($json.email.toLowerCase().trim()).digest('hex');
globalHistory[hash] = new Date().toISOString();
fs.writeFileSync(ghPath, JSON.stringify(globalHistory, null, 2), 'utf8');

return [{ json: { ...$json, draft: $json.response } }];

// Delivered to dashboard "Today's 30" panel -- manual post/mark-done.
// Posting itself stays manual (no compliant automated third-party
// engagement path exists).
const fs = require('fs');
const path = require('path');
let panel = [];
const panelPath = path.join('Shared', 'todays_30.json');
try { panel = JSON.parse(fs.readFileSync(panelPath, 'utf8')); } catch (e) {}
panel.push({ project_prefix: $json.project_prefix, organization: $json.organization, email: $json.email, draft: $json.draft, done: false });
fs.writeFileSync(panelPath, JSON.stringify(panel, null, 2), 'utf8');
return [{ json: $json }];
